// Cache the word map for performance
let _wordMap = null;

function getWordMap() {
  if (_wordMap) return _wordMap;
  _wordMap = {};
  for (const w of COMMON) _wordMap[w] = 1;
  for (const w of UNCOMMON) _wordMap[w] = 2;
  for (const w of RARE) _wordMap[w] = 3;
  return _wordMap;
}

function getTier(word) {
  return getWordMap()[word.toLowerCase()] || 0;
}

function isValid(word) {
  return getTier(word) > 0;
}

function getMultiplier(word) {
  const tier = getTier(word);
  if (tier === 1) return 1;
  if (tier === 2) return 1.5;
  if (tier === 3) return 2;
  return 0;
}

module.exports = { getWordMap, getTier, isValid, getMultiplier, COMMON, UNCOMMON, RARE };
